import html,json
from app import models
from .redaction import redact
TITLE="Unified Threat Correlation and Incident Investigation Report";SECTIONS=["Executive Summary","Case Metadata","Scope and Sources","Primary Entity","Related Entities","Correlation Matches","Cross-Module Observations","Incident Evidence","Risk Score and Contributors","Investigation Timeline","Analyst Notes","Action Items","Resolution Status","Recommended Next Steps","Methodology","Limitations and Confidence","Offline Correlation Disclaimer"]
def esc(v):return html.escape(redact(v,4000))
def generate(db,c):
 vals={s:"No additional local record." for s in SECTIONS};vals.update({"Executive Summary":f"Case {esc(c.case_key)} has local risk score {c.risk_score}/100.","Case Metadata":f"{esc(c.title)} · {esc(c.status)} · {esc(c.priority)} · {esc(c.severity)}","Scope and Sources":f"{c.source_module_count} local modules; {c.evidence_count} safe snapshots.","Primary Entity":str(c.primary_entity_id or "Not assigned"),"Incident Evidence":"<ul>"+"".join(f"<li>{esc(x.title_snapshot)}: {esc(x.evidence_snapshot)}</li>" for x in c.evidence)+"</ul>","Investigation Timeline":"<ul>"+"".join(f"<li>{esc(x.event_type)}: {esc(x.summary)}</li>" for x in c.timeline)+"</ul>","Analyst Notes":"<ul>"+"".join(f"<li>{esc(x.note_text)}</li>" for x in c.notes)+"</ul>","Action Items":"<ul>"+"".join(f"<li>{esc(x.title)} — {esc(x.status)} (workflow task only)</li>" for x in c.actions)+"</ul>","Resolution Status":esc(c.resolution_summary or c.status),"Methodology":"Deterministic evidence-based local correlation of bounded redacted snapshots.","Limitations and Confidence":"A correlated observation is a possible relationship, not confirmed attack attribution.","Offline Correlation Disclaimer":"Local offline correlation only — no indicators or external services were contacted and no real containment occurred."});body="".join(f"<section><h2>{html.escape(s)}</h2><div>{vals[s]}</div></section>" for s in SECTIONS);doc=f"<!doctype html><html><head><meta charset='utf-8'><title>{TITLE}</title><style>body{{font:14px system-ui;max-width:900px;margin:auto}}section{{padding:12px;border-bottom:1px solid #ddd}}</style></head><body><h1>{TITLE}</h1>{body}</body></html>";r=models.IncidentReport(case_id=c.id,title=TITLE,html_content=doc,summary_json=json.dumps({"case_id":c.id,"sections":SECTIONS}));db.add(r);db.flush();from .service import timeline,activity,notify;timeline(db,c,"report_generated",f"Incident report {r.id} generated.");activity(db,"report_generated",f"Incident report {r.id} generated.",c.id);notify(db,"Incident Report Generated",f"Report for {c.case_key} is ready.","success","incident_report",r.id);db.commit();db.refresh(r);return r
